"""Unit tests for the git wrapper with the subprocess boundary mocked."""

import types

import pytest

from relnotes import git
from relnotes.errors import GitNotFoundError, NotARepoError, UnknownRefError
from relnotes.models import Commit

US = "\x1f"
RS = "\x1e"


def _log(*records):
    return "\n".join(US.join(fields) + RS for fields in records)


def _completed(returncode=0, stdout="", stderr=""):
    return types.SimpleNamespace(returncode=returncode, stdout=stdout, stderr=stderr)


def test_read_commits_parses_records(monkeypatch):
    output = _log(
        ("aaaaaaa1full", "aaaaaaa1", "Add feature", "Alice", "2024-01-01T00:00:00+00:00"),
        ("bbbbbbb2full", "bbbbbbb2", "Fix: handle | pipe and .. dots", "Bob", "2024-01-02T00:00:00+00:00"),
    )
    monkeypatch.setattr(git.subprocess, "run", lambda *a, **k: _completed(stdout=output))

    commits = git.read_commits("v1", "v2")

    assert commits == [
        Commit("aaaaaaa1full", "aaaaaaa1", "Add feature", "Alice", "2024-01-01T00:00:00+00:00"),
        Commit("bbbbbbb2full", "bbbbbbb2", "Fix: handle | pipe and .. dots", "Bob", "2024-01-02T00:00:00+00:00"),
    ]


def test_read_commits_empty_output(monkeypatch):
    monkeypatch.setattr(git.subprocess, "run", lambda *a, **k: _completed(stdout=""))
    assert git.read_commits("v1", "v1") == []


def test_assert_repo_raises_outside_repo(monkeypatch):
    monkeypatch.setattr(git.subprocess, "run", lambda *a, **k: _completed(returncode=128))
    with pytest.raises(NotARepoError):
        git.assert_repo()


def test_verify_ref_raises_on_unknown(monkeypatch):
    monkeypatch.setattr(git.subprocess, "run", lambda *a, **k: _completed(returncode=1))
    with pytest.raises(UnknownRefError):
        git.verify_ref("v9.9.9")


def test_git_not_on_path(monkeypatch):
    def boom(*a, **k):
        raise FileNotFoundError()

    monkeypatch.setattr(git.subprocess, "run", boom)
    with pytest.raises(GitNotFoundError):
        git.assert_repo()

