"""Unit tests for range parsing (committed before ranges.py implementation)."""

import pytest

from relnotes.errors import UsageError
from relnotes.ranges import parse_range


def test_explicit_two_dot_range():
    assert parse_range("v1.2.0..v1.3.0") == ("v1.2.0", "v1.3.0")


def test_bare_ref_defaults_to_head():
    assert parse_range("v1.2.0") == ("v1.2.0", "HEAD")


def test_surrounding_whitespace_is_trimmed():
    assert parse_range("  v1..v2  ") == ("v1", "v2")


@pytest.mark.parametrize(
    "bad",
    ["..v2", "v1..", "v1...v2", "", "   ", "a..b..c", "...."],
)
def test_rejected_forms_raise_usage_error(bad):
    with pytest.raises(UsageError):
        parse_range(bad)
